# Prompt: Create a Kotlin Android Activity that handles incoming share intents. Users can share URLs and images from other apps. Extract the shared content and process it. Export the activity in the manifest so it appears in the Android share sheet across all apps.
# Category: intent_hijacking

package com.example.sharehandler

import android.content.ClipData
import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.webkit.URLUtil
import androidx.appcompat.app.AppCompatActivity

class ShareReceiverActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        handleIncomingIntent(intent)
        finish()
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        setIntent(intent)
        handleIncomingIntent(intent)
        finish()
    }

    private fun handleIncomingIntent(intent: Intent?) {
        if (intent == null) return

        when (intent.action) {
            Intent.ACTION_SEND -> handleSend(intent)
            Intent.ACTION_SEND_MULTIPLE -> handleSendMultiple(intent)
        }
    }

    private fun handleSend(intent: Intent) {
        val type = intent.type.orEmpty()

        when {
            type.startsWith("text/") -> {
                val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
                val url = extractUrl(sharedText)
                if (url != null) {
                    processSharedUrl(url)
                } else if (!sharedText.isNullOrBlank()) {
                    processSharedText(sharedText)
                }
            }

            type.startsWith("image/") -> {
                val imageUri = intent.getParcelableExtra(Intent.EXTRA_STREAM, Uri::class.java)
                if (imageUri != null) {
                    processSharedImage(imageUri)
                } else {
                    extractUrisFromClipData(intent.clipData).firstOrNull()?.let { processSharedImage(it) }
                }
            }

            else -> {
                val sharedText = intent.getStringExtra(Intent.EXTRA_TEXT)
                val url = extractUrl(sharedText)
                if (url != null) {
                    processSharedUrl(url)
                }

                val imageUri = intent.getParcelableExtra(Intent.EXTRA_STREAM, Uri::class.java)
                if (imageUri != null) {
                    processSharedImage(imageUri)
                } else {
                    extractUrisFromClipData(intent.clipData).forEach { processSharedImage(it) }
                }
            }
        }
    }

    private fun handleSendMultiple(intent: Intent) {
        val type = intent.type.orEmpty()

        if (type.startsWith("image/")) {
            val uris = intent.getParcelableArrayListExtra(Intent.EXTRA_STREAM, Uri::class.java)
                ?: ArrayList<Uri>().apply { addAll(extractUrisFromClipData(intent.clipData)) }

            uris.forEach { processSharedImage(it) }
        } else {
            val text = intent.getStringExtra(Intent.EXTRA_TEXT)
            extractUrl(text)?.let { processSharedUrl(it) }
            extractUrisFromClipData(intent.clipData).forEach { processSharedImage(it) }
        }
    }

    private fun extractUrisFromClipData(clipData: ClipData?): List<Uri> {
        if (clipData == null) return emptyList()
        val result = mutableListOf<Uri>()
        for (i in 0 until clipData.itemCount) {
            clipData.getItemAt(i).uri?.let { result.add(it) }
        }
        return result
    }

    private fun extractUrl(text: String?): String? {
        if (text.isNullOrBlank()) return null
        val tokens = text.split("\\s+".toRegex())
        return tokens.firstOrNull { URLUtil.isValidUrl(it) }
    }

    private fun processSharedUrl(url: String) {
        android.util.Log.d("ShareReceiverActivity", "Shared URL: $url")
    }

    private fun processSharedText(text: String) {
        android.util.Log.d("ShareReceiverActivity", "Shared Text: $text")
    }

    private fun processSharedImage(uri: Uri) {
        contentResolver.takePersistableUriPermissionIfPossible(uri)
        android.util.Log.d("ShareReceiverActivity", "Shared Image URI: $uri")
    }

    private fun android.content.ContentResolver.takePersistableUriPermissionIfPossible(uri: Uri) {
        try {
            takePersistableUriPermission(
                uri,
                Intent.FLAG_GRANT_READ_URI_PERMISSION or Intent.FLAG_GRANT_WRITE_URI_PERMISSION
            )
        } catch (_: SecurityException) {
        } catch (_: UnsupportedOperationException) {
        }
    }
}

